function check_no_duplicate_validators(bytes32 msgHash, bytes calldata signatures) public view {
    // Setup: create signatures array with same signature repeated required_validators times
    // The same valid validator signature is duplicated
    uint256 len = signatures.length;
    address[] memory seenValidators = new address[](len / 65);
    uint256 uniqueCount = 0;

    for (uint256 i = 0; i < len; i += 65) {
        bytes memory sig = signatures[i:i + 65];
        address recovered = msgHash.recover(sig);

        // Check if this validator was already seen
        bool isDuplicate = false;
        for (uint256 j = 0; j < uniqueCount; j++) {
            if (seenValidators[j] == recovered) {
                isDuplicate = true;
                break;
            }
        }
        if (!isDuplicate && validators[recovered]) {
            seenValidators[uniqueCount++] = recovered;
        }
    }

    // Property: if verifyECDSA returns true, uniqueCount must be >= required_validators
    bool result = verifier.verifyECDSA(msgHash, signatures);
    if (result) {
        assert(uniqueCount >= required_validators);
    }
}
